# =============================================================================
# Helpers
# =============================================================================

clean_text <- function(x) {
  x <- as.character(x)
  x <- gsub("\u00A0", " ", x, fixed = TRUE)
  x <- gsub("[\u200B-\u200D\uFEFF]", "", x)
  x <- trimws(x)
  x[x %in% c("", "NA", "NaN", "NULL", "null")] <- NA_character_
  x
}

parse_bool1 <- function(x, default = FALSE, argname = "") {
  if (is.null(x) || length(x) == 0L) return(as.logical(default)[1])
  
  y <- tolower(clean_text(x[1]))
  
  if (is.na(y) || !nzchar(y)) return(as.logical(default)[1])
  if (y %in% c("true", "t", "1", "yes", "y")) return(TRUE)
  if (y %in% c("false", "f", "0", "no", "n")) return(FALSE)
  
  stop("Cannot parse boolean for ", argname, ": ", x)
}

as_clean_logical <- function(x) {
  if (is.logical(x)) return(x)
  
  y <- tolower(clean_text(x))
  
  out <- rep(NA, length(y))
  out[y %in% c("true", "t", "1", "yes", "y", "reference", "ref")] <- TRUE
  out[y %in% c("false", "f", "0", "no", "n", "query", "intercept")] <- FALSE
  
  out
}

panel_to_groupcol <- function(panel_id) {
  if (grepl("^P1_", panel_id)) return("macroregion_3")
  if (grepl("^P2_", panel_id)) return("subregion")
  if (grepl("^P3_", panel_id)) return("subregion")
  if (grepl("^P4_", panel_id)) return("population")
  if (grepl("macroregion", panel_id, ignore.case = TRUE)) return("macroregion_3")
  if (grepl("subregion", panel_id, ignore.case = TRUE)) return("subregion")
  if (grepl("population", panel_id, ignore.case = TRUE)) return("population")
  "macroregion_3"
}

panel_reference_filter <- function(meta_ref, panel_id) {
  if (grepl("^P1_", panel_id)) {
    return(meta_ref[macroregion_3 %in% c("Africa", "Asia")])
  }
  
  if (grepl("^P2_", panel_id)) {
    return(meta_ref[macroregion_3 == "Africa"])
  }
  
  if (grepl("^P3_", panel_id)) {
    return(meta_ref[macroregion_3 == "Asia"])
  }
  
  meta_ref
}

second_best <- function(v) {
  v2 <- sort(v, decreasing = TRUE)
  if (length(v2) >= 2L) unname(v2[2]) else NA_real_
}

top_name <- function(v) {
  if (length(v) == 0L || all(is.na(v))) return(NA_character_)
  names(which.max(v))[1]
}

conf_label <- function(pmax, gap, n_snps, high, moderate, min_gap, min_snps_query) {
  if (is.na(pmax)) return("Uncertain")
  if (!is.na(n_snps) && n_snps < min_snps_query) return("Uncertain")
  if (!is.na(gap) && gap < min_gap) return("Uncertain")
  if (pmax >= high) return("High")
  if (pmax >= moderate) return("Moderate")
  "Low"
}

make_stratified_folds <- function(y, k = 5, seed = 1) {
  set.seed(seed)
  
  y <- as.factor(y)
  folds <- integer(length(y))
  idx <- seq_along(y)
  
  for (lev in levels(y)) {
    ii <- idx[y == lev]
    ii <- sample(ii, length(ii))
    folds[ii] <- rep(seq_len(k), length.out = length(ii))
  }
  
  folds
}

impute_by_train_means <- function(X_train, X_test = NULL) {
  mu <- colMeans(X_train, na.rm = TRUE)
  mu[is.na(mu)] <- 0.5
  
  X_train2 <- X_train
  
  for (j in seq_len(ncol(X_train2))) {
    miss <- is.na(X_train2[, j])
    if (any(miss)) X_train2[miss, j] <- mu[j]
  }
  
  if (is.null(X_test)) {
    return(list(X_train = X_train2, mu = mu))
  }
  
  X_test2 <- X_test
  
  for (j in seq_len(ncol(X_test2))) {
    miss <- is.na(X_test2[, j])
    if (any(miss)) X_test2[miss, j] <- mu[j]
  }
  
  list(X_train = X_train2, X_test = X_test2, mu = mu)
}

safe_sheet <- function(wb, name) {
  nm <- gsub("[\\[\\]\\*\\?/\\\\:]", "_", name)
  if (nchar(nm) > 31) nm <- substr(nm, 1, 31)
  
  existing <- names(wb)
  if (!(nm %in% existing)) return(nm)
  
  i <- 2
  repeat {
    suffix <- paste0("_", i)
    base <- substr(nm, 1, max(1, 31 - nchar(suffix)))
    nm2 <- paste0(base, suffix)
    if (!(nm2 %in% existing)) return(nm2)
    i <- i + 1
  }
}

safe_pdf <- function(path, width = 8.27, height = 11.69) {
  if ("cairo_pdf" %in% getNamespaceExports("grDevices")) {
    grDevices::cairo_pdf(path, width = width, height = height)
  } else {
    grDevices::pdf(path, width = width, height = height)
  }
}

# =============================================================================
# Random Forest engine
# =============================================================================

have_ranger <- requireNamespace("ranger", quietly = TRUE)
have_rf <- requireNamespace("randomForest", quietly = TRUE)

if (!have_ranger && !have_rf) {
  stop(
    "Step 5 requires either 'ranger' or 'randomForest'.\n",
    "Install one of them, preferably:\n",
    "install.packages('ranger')"
  )
}

fit_rf <- function(X_train, y_train, mtry, trees, min_node_size, seed, cores) {
  y_train <- as.factor(y_train)
  
  if (mtry <= 0) {
    mtry <- max(1L, floor(sqrt(ncol(X_train))))
  }
  
  if (have_ranger) {
    set.seed(seed)
    
    fit <- ranger::ranger(
      x = as.data.frame(X_train),
      y = y_train,
      num.trees = trees,
      mtry = mtry,
      min.node.size = min_node_size,
      probability = TRUE,
      importance = "impurity",
      seed = seed,
      num.threads = cores
    )
    
    return(list(engine = "ranger", fit = fit, levels = levels(y_train)))
  }
  
  set.seed(seed)
  
  fit <- randomForest::randomForest(
    x = X_train,
    y = y_train,
    ntree = trees,
    mtry = mtry,
    importance = TRUE
  )
  
  list(engine = "randomForest", fit = fit, levels = levels(y_train))
}

predict_rf_prob <- function(model, X_test) {
  if (nrow(X_test) == 0L) {
    return(matrix(numeric(0), nrow = 0, ncol = length(model$levels)))
  }
  
  if (model$engine == "ranger") {
    p <- predict(model$fit, data = as.data.frame(X_test))$predictions
  } else {
    p <- predict(model$fit, newdata = X_test, type = "prob")
  }
  
  p <- as.matrix(p)
  
  missing_cols <- setdiff(model$levels, colnames(p))
  
  if (length(missing_cols) > 0L) {
    add <- matrix(
      0,
      nrow = nrow(p),
      ncol = length(missing_cols),
      dimnames = list(rownames(p), missing_cols)
    )
    p <- cbind(p, add)
  }
  
  p <- p[, model$levels, drop = FALSE]
  p
}

get_importance <- function(model) {
  if (model$engine == "ranger") {
    imp <- model$fit$variable.importance
  } else {
    imp <- randomForest::importance(model$fit)
    if (is.matrix(imp)) {
      if ("MeanDecreaseGini" %in% colnames(imp)) {
        imp <- imp[, "MeanDecreaseGini"]
      } else {
        imp <- imp[, 1]
      }
    }
  }
  
  data.table(
    snp_id = names(imp),
    importance = as.numeric(imp)
  )[order(-importance)]
}

summarise_prob_matrix <- function(prob, sample_ids, n_snps_used, high, moderate, min_gap, min_snps_query) {
  if (nrow(prob) == 0L) {
    return(data.table())
  }
  
  rows <- vector("list", nrow(prob))
  
  for (i in seq_len(nrow(prob))) {
    v <- prob[i, ]
    tg <- top_name(v)
    tp <- if (!is.na(tg)) unname(v[tg]) else NA_real_
    sp <- second_best(v)
    sg <- if (length(v) >= 2L) names(sort(v, decreasing = TRUE))[2] else NA_character_
    gap <- if (!is.na(tp) && !is.na(sp)) tp - sp else NA_real_
    
    rows[[i]] <- data.table(
      sample_id = sample_ids[i],
      top_group = tg,
      top_prob = tp,
      second_group = sg,
      second_prob = sp,
      prob_gap = gap,
      n_snps_used = n_snps_used[i],
      confidence = conf_label(
        pmax = tp,
        gap = gap,
        n_snps = n_snps_used[i],
        high = high,
        moderate = moderate,
        min_gap = min_gap,
        min_snps_query = min_snps_query
      )
    )
  }
  
  rbindlist(rows, fill = TRUE)
}

