# =============================================================================
# Run one panel
# =============================================================================

run_panel_rf <- function(panel_id) {
  message("\n============================================================")
  message("Running RF panel: ", panel_id)
  message("============================================================")
  
  panel_dir <- file.path(opt$step3_dir, "panels", panel_id)
  snp_matrix_path <- file.path(panel_dir, "snp_matrix.rds")
  snp_map_path <- file.path(panel_dir, "snp_map.tsv")
  
  if (!file.exists(snp_matrix_path)) {
    warning("Skipping panel; missing: ", snp_matrix_path)
    return(NULL)
  }
  
  if (!file.exists(snp_map_path)) {
    warning("Skipping panel; missing: ", snp_map_path)
    return(NULL)
  }
  
  group_col <- panel_to_groupcol(panel_id)
  
  X0 <- readRDS(snp_matrix_path)
  
  if (!is.matrix(X0)) {
    X0 <- as.matrix(X0)
  }
  
  storage.mode(X0) <- "integer"
  
  if (is.null(rownames(X0)) || is.null(colnames(X0))) {
    stop("SNP matrix for ", panel_id, " lacks rownames or colnames")
  }
  
  meta_ref <- meta[is_reference %in% TRUE]
  meta_ref <- panel_reference_filter(meta_ref, panel_id)
  meta_ref <- meta_ref[!is.na(get(group_col)) & clean_text(get(group_col)) != ""]
  
  ref_ids <- intersect(meta_ref$sample_id, colnames(X0))
  query_ids <- intersect(query_ids_all, colnames(X0))
  
  if (length(ref_ids) == 0L) {
    warning("Skipping ", panel_id, ": no reference samples in matrix")
    return(NULL)
  }
  
  if (length(query_ids) == 0L) {
    warning("Panel ", panel_id, ": no query samples in matrix; validation still runs")
  }
  
  all_panel_ids <- unique(c(ref_ids, query_ids))
  
  keep_snp <- rowMeans(!is.na(X0[, all_panel_ids, drop = FALSE])) >= opt$keep_snps_frac
  X0 <- X0[keep_snp, , drop = FALSE]
  
  if (nrow(X0) == 0L) {
    warning("Skipping ", panel_id, ": no SNPs left after missingness filter")
    return(NULL)
  }
  
  ref_nonmiss <- colSums(!is.na(X0[, ref_ids, drop = FALSE]))
  ref_ids <- ref_ids[ref_nonmiss[ref_ids] >= opt$min_snps_ref]
  
  if (length(ref_ids) == 0L) {
    warning("Skipping ", panel_id, ": no reference samples pass min_snps_ref")
    return(NULL)
  }
  
  meta_ref2 <- meta_ref[sample_id %in% ref_ids]
  class_counts <- meta_ref2[, .N, by = group_col]
  setnames(class_counts, group_col, "class")
  
  keep_classes <- class_counts[N >= opt$min_class_n, class]
  
  meta_ref2 <- meta_ref2[get(group_col) %in% keep_classes]
  ref_ids <- meta_ref2$sample_id
  
  class_counts_final <- meta_ref2[, .N, by = group_col]
  setnames(class_counts_final, group_col, "class")
  
  if (nrow(class_counts_final) < 2L) {
    warning("Skipping ", panel_id, ": fewer than two classes after min_class_n")
    return(NULL)
  }
  
  y_ref <- as.factor(meta_ref2[[group_col]])
  names(y_ref) <- meta_ref2$sample_id
  
  X_ref <- t(X0[, ref_ids, drop = FALSE])
  X_query <- t(X0[, query_ids, drop = FALSE])
  
  n_snps_ref <- rowSums(!is.na(X_ref))
  n_snps_query <- if (length(query_ids) > 0L) rowSums(!is.na(X_query)) else integer(0)
  
  mtry <- opt$mtry
  if (mtry <= 0) {
    mtry <- max(1L, floor(sqrt(ncol(X_ref))))
  }
  
  message("Target:             ", group_col)
  message("Reference samples:  ", nrow(X_ref))
  message("Query samples:      ", nrow(X_query))
  message("SNPs retained:      ", ncol(X_ref))
  message("Classes:            ", paste(class_counts_final$class, class_counts_final$N, sep = "=", collapse = ", "))
  message("RF engine:          ", ifelse(have_ranger, "ranger", "randomForest"))
  
  # ---------------------------------------------------------------------------
  # Repeated stratified k-fold CV
  # ---------------------------------------------------------------------------
  
  cv_rows <- list()
  cv_i <- 1L
  
  min_class <- min(table(y_ref))
  k_eff <- min(opt$folds, min_class)
  
  if (k_eff < 2L) {
    warning("Panel ", panel_id, ": too few samples per class for CV")
    cv_dt <- data.table()
  } else {
    for (rep_i in seq_len(opt$reps)) {
      folds <- make_stratified_folds(y_ref, k = k_eff, seed = opt$seed + rep_i)
      
      for (fold_i in seq_len(k_eff)) {
        test_idx <- which(folds == fold_i)
        train_idx <- setdiff(seq_along(y_ref), test_idx)
        
        X_train <- X_ref[train_idx, , drop = FALSE]
        X_test <- X_ref[test_idx, , drop = FALSE]
        
        y_train <- y_ref[train_idx]
        y_test <- y_ref[test_idx]
        
        imp <- impute_by_train_means(X_train, X_test)
        
        model <- fit_rf(
          X_train = imp$X_train,
          y_train = y_train,
          mtry = mtry,
          trees = opt$trees,
          min_node_size = opt$min_node_size,
          seed = opt$seed + rep_i * 1000 + fold_i,
          cores = opt$cores
        )
        
        prob <- predict_rf_prob(model, imp$X_test)
        
        pred_dt <- summarise_prob_matrix(
          prob = prob,
          sample_ids = names(y_test),
          n_snps_used = rowSums(!is.na(X_test)),
          high = opt$high_prob,
          moderate = opt$moderate_prob,
          min_gap = opt$min_gap,
          min_snps_query = 0
        )
        
        pred_dt[, `:=`(
          panel_id = panel_id,
          group_col = group_col,
          rep = rep_i,
          fold = fold_i,
          true_group = as.character(y_test),
          correct = top_group == as.character(y_test)
        )]
        
        cv_rows[[cv_i]] <- pred_dt
        cv_i <- cv_i + 1L
      }
    }
    
    cv_dt <- rbindlist(cv_rows, fill = TRUE)
  }
  
  if (nrow(cv_dt) > 0L) {
    cv_summary <- cv_dt[
      ,
      .(
        n = .N,
        accuracy = mean(correct, na.rm = TRUE),
        mean_top_prob = mean(top_prob, na.rm = TRUE),
        median_top_prob = median(top_prob, na.rm = TRUE),
        mean_gap = mean(prob_gap, na.rm = TRUE),
        high_or_moderate_frac = mean(confidence %in% c("High", "Moderate"), na.rm = TRUE)
      ),
      by = .(panel_id, group_col)
    ]
    
    cv_perclass <- cv_dt[
      ,
      .(
        n = .N,
        accuracy = mean(correct, na.rm = TRUE),
        mean_top_prob = mean(top_prob, na.rm = TRUE),
        high_or_moderate_frac = mean(confidence %in% c("High", "Moderate"), na.rm = TRUE)
      ),
      by = .(panel_id, true_group)
    ][order(true_group)]
    
  } else {
    cv_summary <- data.table(
      panel_id = panel_id,
      group_col = group_col,
      n = 0L,
      accuracy = NA_real_,
      mean_top_prob = NA_real_,
      median_top_prob = NA_real_,
      mean_gap = NA_real_,
      high_or_moderate_frac = NA_real_
    )
    
    cv_perclass <- data.table()
  }
  
  # ---------------------------------------------------------------------------
  # Train final model and predict queries
  # ---------------------------------------------------------------------------
  
  imp_final <- impute_by_train_means(X_ref)
  
  final_model <- fit_rf(
    X_train = imp_final$X_train,
    y_train = y_ref,
    mtry = mtry,
    trees = opt$trees,
    min_node_size = opt$min_node_size,
    seed = opt$seed,
    cores = opt$cores
  )
  
  var_imp <- get_importance(final_model)
  
  if (length(query_ids) > 0L) {
    imp_query <- impute_by_train_means(X_ref, X_query)
    prob_query <- predict_rf_prob(final_model, imp_query$X_test)
    
    pred_query <- summarise_prob_matrix(
      prob = prob_query,
      sample_ids = query_ids,
      n_snps_used = n_snps_query[query_ids],
      high = opt$high_prob,
      moderate = opt$moderate_prob,
      min_gap = opt$min_gap,
      min_snps_query = opt$min_snps_query
    )
    
    pred_query[, `:=`(
      panel_id = panel_id,
      group_col = group_col,
      status = fifelse(n_snps_used < opt$min_snps_query, "too_few_snps", "ok")
    )]
    
    meta_cols <- intersect(
      c("sample_id", "country", "population", "macroregion_3", "subregion", "is_reference"),
      names(meta)
    )
    
    pred_query <- merge(
      pred_query,
      meta[, ..meta_cols],
      by = "sample_id",
      all.x = TRUE,
      sort = FALSE
    )
    
    if (nrow(step4_final) > 0L) {
      pred_query <- merge(
        pred_query,
        step4_final,
        by = "sample_id",
        all.x = TRUE,
        sort = FALSE
      )
      
      pred_query[, rf_vs_step4 := NA_character_]
      
      if (grepl("^P1_", panel_id)) {
        pred_query[
          !is.na(macroregion_call) & !is.na(top_group),
          rf_vs_step4 := fifelse(
            top_group == macroregion_call,
            "supports_step4_macroregion",
            "discordant_with_step4_macroregion"
          )
        ]
        
        pred_query[
          is.na(macroregion_call) | macroregion_confidence == "Uncertain",
          rf_vs_step4 := "step4_macroregion_uncertain"
        ]
      }
      
      if (grepl("^P2_", panel_id)) {
        pred_query[
          !is.na(subregion_call) & !is.na(top_group),
          rf_vs_step4 := fifelse(
            top_group == subregion_call,
            "supports_step4_subregion",
            "discordant_with_step4_subregion"
          )
        ]
        
        pred_query[
          !is.na(macroregion_call) & macroregion_call != "Africa",
          rf_vs_step4 := "not_interpreted_step4_not_africa"
        ]
        
        pred_query[
          is.na(subregion_call) | subregion_confidence == "Uncertain",
          rf_vs_step4 := fifelse(
            rf_vs_step4 %in% c("not_interpreted_step4_not_africa"),
            rf_vs_step4,
            "step4_subregion_uncertain"
          )
        ]
      }
      
      if (grepl("^P3_", panel_id)) {
        pred_query[
          !is.na(subregion_call) & !is.na(top_group),
          rf_vs_step4 := fifelse(
            top_group == subregion_call,
            "supports_step4_subregion",
            "discordant_with_step4_subregion"
          )
        ]
        
        pred_query[
          !is.na(macroregion_call) & macroregion_call != "Asia",
          rf_vs_step4 := "not_interpreted_step4_not_asia"
        ]
        
        pred_query[
          is.na(subregion_call) | subregion_confidence == "Uncertain",
          rf_vs_step4 := fifelse(
            rf_vs_step4 %in% c("not_interpreted_step4_not_asia"),
            rf_vs_step4,
            "step4_subregion_uncertain"
          )
        ]
      }
    }
    
  } else {
    pred_query <- data.table()
  }
  
  # ---------------------------------------------------------------------------
  # Write panel outputs
  # ---------------------------------------------------------------------------
  
  safe_panel <- gsub("[^A-Za-z0-9_]+", "_", panel_id)
  
  pred_file <- file.path(opt$out_dir, paste0("RF_", safe_panel, "_predictions_queries.tsv"))
  cv_sum_file <- file.path(opt$out_dir, paste0("RF_", safe_panel, "_cv_summary.tsv"))
  cv_pc_file <- file.path(opt$out_dir, paste0("RF_", safe_panel, "_cv_perclass.tsv"))
  cv_rows_file <- file.path(opt$out_dir, paste0("RF_", safe_panel, "_cv_rows.tsv"))
  imp_file <- file.path(opt$out_dir, paste0("RF_", safe_panel, "_variable_importance.tsv"))
  fig_file <- file.path(opt$out_dir, paste0("FIG_RF_", safe_panel, "_validation_A4.pdf"))
  
  fwrite(pred_query, pred_file, sep = "\t")
  fwrite(cv_summary, cv_sum_file, sep = "\t")
  fwrite(cv_perclass, cv_pc_file, sep = "\t")
  fwrite(var_imp, imp_file, sep = "\t")
  
  if (isTRUE(write_cv_rows)) {
    fwrite(cv_dt, cv_rows_file, sep = "\t")
  }
  
  # ---------------------------------------------------------------------------
  # Simple A4 validation figure
  # ---------------------------------------------------------------------------
  
  safe_pdf(fig_file)
  
  oldpar <- par(no.readonly = TRUE)
  on.exit(par(oldpar), add = TRUE)
  
  par(mfrow = c(3, 1), mar = c(5, 5, 4, 2))
  
  if (nrow(cv_perclass) > 0L) {
    barplot(
      cv_perclass$accuracy,
      names.arg = cv_perclass$true_group,
      las = 2,
      ylim = c(0, 1),
      main = paste0(panel_id, "\nCV accuracy by class"),
      ylab = "Accuracy"
    )
    abline(h = cv_summary$accuracy[1], lty = 2)
  } else {
    plot.new()
    title("No CV per-class results")
  }
  
  if (nrow(cv_dt) > 0L) {
    boxplot(
      top_prob ~ true_group,
      data = cv_dt,
      las = 2,
      ylim = c(0, 1),
      main = "CV top probability by true class",
      ylab = "Top RF probability"
    )
  } else {
    plot.new()
    title("No CV probability results")
  }
  
  if (nrow(pred_query) > 0L) {
    barplot(
      table(pred_query$top_group),
      las = 2,
      main = "Query predicted classes",
      ylab = "Number of queries"
    )
  } else {
    plot.new()
    title("No query predictions")
  }
  
  dev.off()
  
  panel_index <- data.table(
    panel_id = panel_id,
    group_col = group_col,
    engine = ifelse(have_ranger, "ranger", "randomForest"),
    n_snps_retained = ncol(X_ref),
    n_reference_samples = nrow(X_ref),
    n_query_samples = nrow(X_query),
    n_classes = nrow(class_counts_final),
    classes = paste(class_counts_final$class, class_counts_final$N, sep = "=", collapse = ","),
    cv_accuracy = cv_summary$accuracy[1],
    cv_mean_top_prob = cv_summary$mean_top_prob[1],
    query_high = if (nrow(pred_query) > 0L) sum(pred_query$confidence == "High", na.rm = TRUE) else 0L,
    query_moderate = if (nrow(pred_query) > 0L) sum(pred_query$confidence == "Moderate", na.rm = TRUE) else 0L,
    query_low = if (nrow(pred_query) > 0L) sum(pred_query$confidence == "Low", na.rm = TRUE) else 0L,
    query_uncertain = if (nrow(pred_query) > 0L) sum(pred_query$confidence == "Uncertain", na.rm = TRUE) else 0L,
    predictions_file = pred_file,
    cv_summary_file = cv_sum_file,
    cv_perclass_file = cv_pc_file,
    cv_rows_file = if (isTRUE(write_cv_rows)) cv_rows_file else NA_character_,
    importance_file = imp_file,
    figure_file = fig_file
  )
  
  list(
    index = panel_index,
    pred = pred_query,
    cv_summary = cv_summary,
    cv_perclass = cv_perclass,
    cv_rows = cv_dt,
    importance = var_imp
  )
}

# =============================================================================
# Run panels
# =============================================================================

panel_results <- list()

for (p in panels) {
  res <- run_panel_rf(p)
  if (!is.null(res)) {
    panel_results[[p]] <- res
  }
}

if (length(panel_results) == 0L) {
  stop("No panels completed successfully.")
}

index_dt <- rbindlist(lapply(panel_results, `[[`, "index"), fill = TRUE)

fwrite(index_dt, file.path(opt$out_dir, "step5_rf_panels_index.tsv"), sep = "\t")
saveRDS(index_dt, file.path(opt$out_dir, "step5_rf_panels_index.rds"))

all_pred <- rbindlist(lapply(panel_results, `[[`, "pred"), fill = TRUE)
all_cv_summary <- rbindlist(lapply(panel_results, `[[`, "cv_summary"), fill = TRUE)
all_cv_perclass <- rbindlist(lapply(panel_results, `[[`, "cv_perclass"), fill = TRUE)

fwrite(all_pred, file.path(opt$out_dir, "RF_all_panels_predictions_queries.tsv"), sep = "\t")
fwrite(all_cv_summary, file.path(opt$out_dir, "RF_all_panels_cv_summary.tsv"), sep = "\t")
fwrite(all_cv_perclass, file.path(opt$out_dir, "RF_all_panels_cv_perclass.tsv"), sep = "\t")

saveRDS(all_pred, file.path(opt$out_dir, "RF_all_panels_predictions_queries.rds"))
saveRDS(all_cv_summary, file.path(opt$out_dir, "RF_all_panels_cv_summary.rds"))
saveRDS(all_cv_perclass, file.path(opt$out_dir, "RF_all_panels_cv_perclass.rds"))

