wb <- createWorkbook()

sn <- safe_sheet(wb, "PANELS_INDEX")
addWorksheet(wb, sn)
writeDataTable(wb, sn, index_dt)

sn <- safe_sheet(wb, "ALL_QUERY_PREDICTIONS")
addWorksheet(wb, sn)
writeDataTable(wb, sn, all_pred)

sn <- safe_sheet(wb, "CV_SUMMARY")
addWorksheet(wb, sn)
writeDataTable(wb, sn, all_cv_summary)

sn <- safe_sheet(wb, "CV_PERCLASS")
addWorksheet(wb, sn)
writeDataTable(wb, sn, all_cv_perclass)

params <- data.table(
  parameter = names(opt),
  value = vapply(opt, function(x) paste(x, collapse = ","), character(1))
)

params <- rbind(
  params,
  data.table(parameter = "write_cv_rows_parsed", value = as.character(write_cv_rows)),
  fill = TRUE
)

