# Run info
# =============================================================================

run_info <- list(
  step = "step5_random_forest_origin_tracing",
  repo_root = repo_root,
  qc_dir = opt$qc_dir,
  step3_dir = opt$step3_dir,
  step4_dir = opt$step4_dir,
  out_dir = opt$out_dir,
  panels = panels,
  engine = ifelse(have_ranger, "ranger", "randomForest"),
  write_cv_rows = write_cv_rows,
  parameters = opt,
  panel_index = index_dt,
  timestamp = Sys.time(),
  session_info = sessionInfo()
)

saveRDS(run_info, file.path(opt$out_dir, "step5_run_info.rds"))

message("\nDone.")
message("RF panel index:   ", file.path(opt$out_dir, "step5_rf_panels_index.tsv"))
message("All predictions:  ", file.path(opt$out_dir, "RF_all_panels_predictions_queries.tsv"))
